import { FORMATIONS, FORMATION_COORDS, RARITIES, CARD_STAGGER_MS, DRAW_TICK_MS, DRAW_COUNTRY_TICKS, DRAW_YEAR_TICKS, DRAW_SETTLE_MS, DRAFT_TIMER_MS, positionLabel, rarityOf } from './config.js';
import { game, activePlayer, resetGame } from './state.js';
import { drawRound, compatibleSlot, selectCard as commitSelection, completeDraft, autoDraft, autoDraftByDifficulty, shuffle } from './draft-engine.js';
import { PLAYERS, achievementOf } from './players.js';
import { runMatch } from './simulator.js';
import { COACHES, chemistry, coachData, teamPower, winProbabilities } from './competitive.js';
import { leaveOnlineRoom, onlineRoomRequest, watchOnlineRoom } from './supabase-online.js';
import { openTournament } from './tournament.js';

const app=document.querySelector('#app');const referees=['Pierluigi Collina','Howard Webb','Néstor Pitana','Sándor Puhl','Nicola Rizzoli'];
const sleep=ms=>new Promise(r=>setTimeout(r,ms));const toast=t=>{const e=document.querySelector('#toast');e.textContent=t;e.classList.add('show');setTimeout(()=>e.classList.remove('show'),1800)};
const escapeHTML=value=>String(value??'').replace(/[&<>'"]/g,char=>({'&':'&amp;','<':'&lt;','>':'&gt;',"'":'&#39;','"':'&quot;'}[char]));
let audioContext;function playTone(frequency=520,duration=.18){if(!game.sound)return;try{audioContext??=new AudioContext();const oscillator=audioContext.createOscillator(),gain=audioContext.createGain();oscillator.type='sine';oscillator.frequency.value=frequency;gain.gain.setValueAtTime(.0001,audioContext.currentTime);gain.gain.exponentialRampToValueAtTime(.12,audioContext.currentTime+.02);gain.gain.exponentialRampToValueAtTime(.0001,audioContext.currentTime+duration);oscillator.connect(gain).connect(audioContext.destination);oscillator.start();oscillator.stop(audioContext.currentTime+duration)}catch{}}
const online={code:'',token:'',role:'',deadline:0,pollId:0,timerId:0,unsubscribe:null,started:false,ending:false,resultShown:false,watching:false,guestPromptId:'',remoteDecision:null};let lastVisualLog='',lastFieldEvent='',lastPenaltyVisual='',lastResultKey='',currentMatchLabels={home:'CASA',away:'FORA'};
async function roomRequest(path,options={}){return onlineRoomRequest(path,options)}
function clearOnline(){if(online.code&&online.token)leaveOnlineRoom(online.code);clearInterval(online.pollId);clearInterval(online.timerId);online.unsubscribe?.();Object.assign(online,{code:'',token:'',role:'',deadline:0,pollId:0,timerId:0,unsubscribe:null,started:false,ending:false,resultShown:false,watching:false,guestPromptId:'',remoteDecision:null});document.querySelector('#onlineTimer').hidden=true}
function onlineMenu(){shell(`<section class="screen online-menu"><div class="section-head"><div><div class="step">MULTIPLAYER ONLINE</div><h2>Jogue com um amigo</h2></div><button class="btn" data-home>← Voltar</button></div><div class="online-grid"><div class="panel"><div class="online-icon">＋</div><h2>Criar sala</h2><p class="lead">Gere um código e envie para seu amigo. O cronômetro começa quando ele entrar.</p><button class="btn primary" data-create-room>Criar sala</button></div><form class="panel" id="joinForm"><div class="online-icon">#</div><h2>Entrar na sala</h2><p class="lead">Digite o código de seis caracteres recebido.</p><input class="room-input" id="roomCode" maxlength="6" autocomplete="off" placeholder="ABC123" aria-label="Código da sala" required><button class="btn primary">Entrar</button></form></div></section>`);bind();document.querySelector('[data-create-room]').onclick=createOnlineRoom;document.querySelector('#joinForm').onsubmit=event=>{event.preventDefault();joinOnlineRoom(document.querySelector('#roomCode').value)}}
async function createOnlineRoom(){try{const data=await roomRequest('/api/rooms',{method:'POST',body:'{}'});Object.assign(online,data);onlineLobby();startRoomPolling()}catch(error){toast(error.message)}}
async function joinOnlineRoom(code){try{const normalized=code.trim().toUpperCase();if(normalized.length!==6)throw new Error('Digite um código válido.');const data=await roomRequest(`/api/rooms/${normalized}/join`,{method:'POST',body:'{}'});Object.assign(online,data);beginOnlineDraft()}catch(error){toast(error.message)}}
function onlineLobby(){shell(`<section class="screen handoff"><div class="room-wait"><div class="eyebrow">SALA CRIADA</div><span class="room-code">${online.code}</span><p class="lead">Envie este código ao seu amigo. A partida começa automaticamente quando ele entrar.</p><button class="btn" data-copy-code>Copiar código</button><div class="waiting-pulse"><i></i> Aguardando Jogador 2...</div></div></section>`);document.querySelector('[data-copy-code]').onclick=async()=>{await navigator.clipboard?.writeText(online.code);toast('Código copiado!')}}
function startRoomPolling(){clearInterval(online.pollId);online.unsubscribe?.();online.unsubscribe=watchOnlineRoom(online.code,pollOnlineRoom);online.pollId=setInterval(pollOnlineRoom,2000);pollOnlineRoom()}
async function pollOnlineRoom(){if(!online.code||!online.token)return;try{const data=await roomRequest(`/api/rooms/${online.code}`);if(data.deadline)online.deadline=data.deadline;online.remoteDecision=online.role==='host'?data.guestDecision:data.hostDecision;if(data.connected&&!online.started)beginOnlineDraft();if(online.watching&&data.match?.score){renderMatchState(data.match);if(data.match.interaction?.side==='away'&&online.role==='guest'&&online.guestPromptId!==data.match.interaction.id)promptGuestDecision(data.match.interaction);return}if(online.started&&!online.resultShown){const rival=online.role==='host'?data.guest:data.host;if((rival?.finished||data.deadline<=Date.now())&&activePlayer().finishedDraft){online.resultShown=true;showOnlineResult(rival)}}}catch(error){if(error.status===404&&online.role==='guest'){clearOnline();resetGame();home();toast('O criador encerrou a sala.');return}if(online.started)toast(error.message)}}
function beginOnlineDraft(){if(online.started)return;online.started=true;resetGame('online');activePlayer().side=online.role==='host'?'home':'away';startRoomPolling();startDraftTimer(online.deadline,true);chooseSide(true)}
function stopDraftTimer(){clearInterval(online.timerId);online.timerId=0;const timer=document.querySelector('#onlineTimer');timer.hidden=true;timer.classList.remove('urgent')}
function startDraftTimer(deadline,isOnline=false){const timer=document.querySelector('#onlineTimer');timer.hidden=false;clearInterval(online.timerId);const tick=()=>{const remaining=Math.min(DRAFT_TIMER_MS,Math.max(0,deadline-Date.now())),seconds=Math.ceil(remaining/1000);timer.textContent=`${String(Math.floor(seconds/60)).padStart(2,'0')}:${String(seconds%60).padStart(2,'0')}`;timer.classList.toggle('urgent',seconds<=20);if(!remaining){isOnline?finishOnlineByTimer():finishLocalDraftByTimer()}};tick();online.timerId=setInterval(tick,250)}
function finishLocalDraftByTimer(){if(game.locked){setTimeout(finishLocalDraftByTimer,400);return}const p=activePlayer();stopDraftTimer();try{completeDraft(p);toast('Tempo encerrado. As vagas restantes foram preenchidas.');coach()}catch(error){toast(error.message)}}
async function syncOnline(){if(game.mode!=='online'||!online.code)return;const p=activePlayer(),body={side:p.side,formation:p.formation,lineupIds:p.lineup.filter(Boolean).map(card=>card.id),progress:p.currentRound,coach:p.coach,captainId:p.captainId,strategy:p.strategy,finished:p.finishedDraft};try{await roomRequest(`/api/rooms/${online.code}/state`,{method:'PUT',body:JSON.stringify(body)})}catch(error){toast(error.message)}}
function finishOnlineByTimer(){if(online.ending)return;if(game.locked){setTimeout(finishOnlineByTimer,500);return}online.ending=true;const p=activePlayer();if(p.finishedDraft){onlineWaiting();return}try{if(!p.formation)p.formation='4-3-3';completeDraft(p);p.coach||=shuffle(COACHES)[0].name;p.captainId||=p.team[0]?.id;p.finishedDraft=true;syncOnline();onlineWaiting()}catch(error){online.ending=false;toast(error.message)}}
function onlineWaiting(){shell(`<section class="screen handoff"><div><div class="eyebrow">SEU TIME ESTÁ PRONTO</div><h2 class="page-title">Aguardando <span>o adversário</span></h2><p class="lead">Ele ainda está escolhendo jogadores, capitão ou treinador. A partida só avança quando os dois times estiverem prontos.</p><div class="waiting-pulse"><i></i> Sala ${online.code}</div></div></section>`)}
function showOnlineResult(rival){clearInterval(online.timerId);document.querySelector('#onlineTimer').hidden=true;const byId=new Map(PLAYERS.map(card=>[card.id,card]));game.opponent={side:activePlayer().side==='home'?'away':'home',formation:rival.formation||'4-3-3',team:(rival.lineupIds||[]).map(id=>byId.get(id)).filter(Boolean),coach:rival.coach||'Técnico automático',captainId:rival.captainId||'',strategy:rival.strategy||'balanced'};if(game.opponent.team.length<11){const fallback=autoDraft(game.opponent.formation);game.opponent.team=[...game.opponent.team,...fallback.filter(card=>!game.opponent.team.some(item=>item.id===card.id))].slice(0,11)}game.opponent.captainId||=game.opponent.team[0]?.id;summary()}
function shell(content,extra=''){app.className=extra;const isHome=content.includes('screen hero');app.innerHTML=`${isHome?'':`<button class="global-back" data-home aria-label="Voltar ao menu inicial" title="Voltar ao menu">←</button>`}${content}`;const back=app.querySelector('[data-home]');if(back)back.onclick=()=>{clearOnline();resetGame();home()};requestAnimationFrame(()=>app.classList.add('screen-in'))}
function home(){const countries=new Set(PLAYERS.map(player=>player.country)).size;shell(`<section class="screen hero"><div class="hero-copy"><div class="eyebrow">✦ EDDY CUP LEGENDS • UMA ÚNICA SELEÇÃO.</div><h1>Monte.<br><span>Domine.</span>Vire lenda.</h1><p class="lead">Escolha os maiores nomes da história das Copas, construa seu onze perfeito e descubra se suas lendas conseguem conquistar o jogo eterno.</p><div class="actions hero-actions"><button class="btn primary" data-mode="solo">▶ Jogar solo</button><button class="btn" data-mode="local">Multiplayer local</button><button class="btn" data-online>Jogar online</button><button class="btn player-search-btn" data-players>⌕ Pesquisar jogadores</button><button class="btn tournament-menu-btn" data-tournament>🏆 Criar torneio</button><button class="btn how-to-btn" data-info>Como jogar</button></div><div class="hero-proof"><span><b>${PLAYERS.length}</b> jogadores</span><span><b>${countries}</b> seleções</span><span><b>3</b> modos de jogo</span></div></div><div class="hero-card"><div class="hero-card-label"><span>EDDY CUP</span><b>LEGENDS</b><small>DRAFT • SIMULE • DOMINE</small></div><div class="orbit"></div><div class="trophy"></div></div></section>`);bind()}
function playerExplorer(){
  const countries=[...new Set(PLAYERS.map(player=>player.country))].sort((a,b)=>a.localeCompare(b,'pt-BR')),years=[...new Set(PLAYERS.map(player=>player.year))].sort((a,b)=>b-a),pageSize=48;
  shell(`<section class="screen explorer-screen"><div class="section-head"><div><div class="step">BANCO DE LENDAS</div><h2>Pesquisar jogadores</h2></div><div class="explorer-total"><b>${PLAYERS.length}</b><span>jogadores • ${countries.length} seleções</span></div></div><div class="explorer-tools panel"><label><span>NOME DO JOGADOR</span><input id="playerSearch" type="search" autocomplete="off" placeholder="Ex.: Ronaldo, Messi, Mbappé..."></label><label><span>SELEÇÃO</span><select id="countryFilter"><option value="">Todas as seleções</option>${countries.map(country=>`<option>${country}</option>`).join('')}</select></label><label><span>ANO</span><select id="yearFilter"><option value="">Todos os anos</option>${years.map(year=>`<option>${year}</option>`).join('')}</select></label><button class="btn" id="clearPlayerSearch">Limpar</button></div><div class="explorer-meta"><p id="explorerCount"></p><div id="explorerPager" class="explorer-pager"></div></div><div id="playerResults" class="player-results"></div></section>`);
  const search=document.querySelector('#playerSearch'),country=document.querySelector('#countryFilter'),year=document.querySelector('#yearFilter'),results=document.querySelector('#playerResults'),count=document.querySelector('#explorerCount'),pager=document.querySelector('#explorerPager');let page=1;
  const normalize=value=>value.normalize('NFD').replace(/[\u0300-\u036f]/g,'').toLowerCase(),render=()=>{const query=normalize(search.value.trim()),filtered=PLAYERS.filter(player=>(!query||normalize(player.name).includes(query))&&(!country.value||player.country===country.value)&&(!year.value||player.year===+year.value)),pages=Math.max(1,Math.ceil(filtered.length/pageSize));page=Math.min(page,pages);const visible=filtered.slice((page-1)*pageSize,page*pageSize);count.innerHTML=filtered.length?`<b>${filtered.length}</b> jogador${filtered.length===1?'':'es'} encontrado${filtered.length===1?'':'s'}${country.value?` em <strong>${country.value}</strong>`:''}`:'Nenhum jogador existente no jogo com esses filtros.';results.innerHTML=visible.length?visible.map(player=>`<article class="explorer-player"><div><strong>${player.overall}</strong><span>${positionLabel(player.position)}</span></div><section><b>${player.name}</b><small>${player.country} • Copa de ${player.year}</small>${achievementOf(player)?`<em>★ ${achievementOf(player)}</em>`:''}</section></article>`).join(''):`<div class="explorer-empty"><span>?</span><h3>Jogador não existente no jogo</h3><p>Tente outro nome ou limpe os filtros. A busca considera todos os ${PLAYERS.length} jogadores cadastrados.</p></div>`;pager.innerHTML=pages>1?`<button ${page===1?'disabled':''} data-page="${page-1}">←</button><span>Página ${page} de ${pages}</span><button ${page===pages?'disabled':''} data-page="${page+1}">→</button>`:'';pager.querySelectorAll('[data-page]').forEach(button=>button.onclick=()=>{page=+button.dataset.page;render()})};
  [search,country,year].forEach(input=>input.addEventListener(input===search?'input':'change',()=>{page=1;render()}));document.querySelector('#clearPlayerSearch').onclick=()=>{search.value='';country.value='';year.value='';page=1;render()};render();search.focus();
}
function howToPlay(){const slides=[['01','Escolha o modo','No Solo, escolha a dificuldade. No Local, dois jogadores usam o mesmo aparelho em telas separadas. No Online, compartilhe o código da sala.','SOLO • LOCAL • ONLINE'],['02','Defina lado e formação','Escolha casa ou fora e monte o campo em 4-3-3, 4-4-2 ou 3-5-2. Cada esquema muda de verdade a posição dos jogadores.','FORMAÇÃO É ESTRATÉGIA'],['03','Monte suas lendas','A cada rodada surge uma seleção e uma Copa. Escolha uma carta compatível com uma vaga aberta ou use um dos seus rerolls.','11 ESCOLHAS • 3 REROLLS'],['04','Crie química','Jogadores do mesmo país ou de épocas próximas melhoram a química. Quanto maior a química, maior sua chance de vitória. Cada lenda soma +2%.','QUÍMICA 0–100'],['05','Capitão e treinador','Escolha o líder, o treinador e o estilo de jogo. Overall, estratégia e histórico do técnico entram no cálculo de força.','CADA DECISÃO CONTA'],['06','Decida a partida','Reaja aos eventos, bata pênaltis e escolha os cobradores. Nos pênaltis, o overall do batedor enfrenta o overall do goleiro.','VENÇA NO DETALHE']];let index=0;const render=()=>{const [number,title,text,tag]=slides[index];shell(`<section class="screen tutorial-screen"><div class="tutorial-wrap"><div class="tutorial-progress">${slides.map((_,i)=>`<i class="${i===index?'active':''}"></i>`).join('')}</div><div class="tutorial-card"><span>${number} / 06</span><h2>${title}</h2><p>${text}</p><strong>${tag}</strong></div><div class="tutorial-controls"><button class="btn" data-tutorial-prev ${index===0?'disabled':''}>← Anterior</button><small>Use as setas para navegar</small><button class="btn primary" data-tutorial-next>${index===slides.length-1?'Começar a jogar':'Próxima →'}</button></div></div></section>`);document.querySelector('[data-tutorial-prev]')?.addEventListener('click',()=>{index--;render()});document.querySelector('[data-tutorial-next]').onclick=()=>{if(index===slides.length-1)home();else{index++;render()}}};render()}
function chooseDifficulty(){const levels=[['easy','Fácil','Adversário menos estrelado','OVR menor • poucas lendas'],['medium','Médio','Equilíbrio recomendado','Elenco competitivo • lendas ocasionais'],['hard','Difícil','Seleção de alto nível','OVR alto • mais épicos e lendas'],['legendary','Lendário','Um verdadeiro World XI','Elite histórica • muitas lendas']];shell(`<section class="screen difficulty-screen"><div class="section-head"><div><div class="step">MODO SOLO • NÍVEL DO ADVERSÁRIO</div><h2>Escolha a dificuldade</h2></div></div><div class="difficulty-grid">${levels.map(([id,name,desc,note],index)=>`<button class="difficulty-card ${id}" data-difficulty="${id}"><span>0${index+1}</span><h3>${name}</h3><p>${desc}</p><small>${note}</small></button>`).join('')}</div><p class="game-note">A dificuldade altera a qualidade dos jogadores, a quantidade provável de lendas e o índice do treinador adversário. Seu draft não é prejudicado.</p></section>`);document.querySelectorAll('[data-difficulty]').forEach(button=>button.onclick=()=>{game.difficulty=button.dataset.difficulty;chooseSide()})}
function chooseSide(locked=false){const p=activePlayer(),label=game.mode==='local'?'JOGADOR 1':game.mode==='online'?(online.role==='host'?'CRIADOR DA SALA':'CONVIDADO'):'VOCÊ';shell(`<section class="screen side-screen"><div class="section-head"><div><div class="step">${label} • CONFIGURAÇÃO DA PARTIDA</div><h2>Escolha o seu lado</h2></div></div><div class="side-grid"><button class="choice side-choice ${p.side==='home'?'selected-side':''}" data-side="home" ${locked&&p.side!=='home'?'disabled':''}><span class="num">⌂</span><h3>Time da casa</h3><p>Você será o mandante e aparecerá no lado esquerdo.</p></button><div class="versus-mark">VS<small>MANDANTE × VISITANTE</small></div><button class="choice side-choice ${p.side==='away'?'selected-side':''}" data-side="away" ${locked&&p.side!=='away'?'disabled':''}><span class="num">✈</span><h3>Time de fora</h3><p>Você será o visitante e aparecerá no lado direito.</p></button></div>${locked?`<p class="side-note">No Online, quem cria a sala joga em casa e quem entra joga fora.</p>`:''}</section>`);document.querySelectorAll('[data-side]').forEach(button=>button.onclick=()=>{p.side=button.dataset.side;if(game.mode==='local')game.players.player2.side=p.side==='home'?'away':'home';chooseFormation()});if(locked)setTimeout(()=>document.querySelector(`[data-side="${p.side}"]`)?.click(),650)}
function chooseFormation(){const p=activePlayer();shell(`<section class="screen"><div class="section-head"><div><div class="step">${game.mode==='local'?`JOGADOR ${game.active==='player1'?1:2} • `:''}ETAPA 01 / 04</div><h2>Escolha sua formação</h2></div><button class="btn" data-home>← Voltar</button></div><div class="grid">${Object.keys(FORMATIONS).map((f,i)=>`<button class="choice" data-formation="${f}"><span class="num">0${i+1}</span><h3>${f}</h3><p>${f==='4-3-3'?'Amplitude e poder ofensivo':f==='4-4-2'?'Equilíbrio clássico entre setores':'Domínio do meio-campo'}</p></button>`).join('')}</div></section>`);bind()}
const avatar=()=>`<span class="avatar" aria-hidden="true"><i></i></span>`;
function cardHTML(p,i){const r=rarityOf(p.overall),blocked=compatibleSlot(activePlayer(),p.position)<0,achievement=achievementOf(p);return `<button class="player-card ${r} ${blocked?'blocked':''}" data-pick="${i}" style="--delay:${i*CARD_STAGGER_MS}ms" ${blocked?'disabled aria-disabled="true" title="Posição já preenchida"':''}><span class="rarity-tag">${RARITIES[r].label}</span><span class="rating"><small>OVR</small>${p.overall}</span>${achievement?`<span class="achievement-badge">★ ${achievement}</span>`:''}${blocked?'<span class="blocked-label">POSIÇÃO PREENCHIDA</span>':''}${avatar()}<h3>${p.name}</h3><div class="card-details"><b>${positionLabel(p.position)}</b><span>${p.country} — ${p.year}</span></div></button>`}
function pitchHTML(p,preview=false){const coords=FORMATION_COORDS[p.formation]||FORMATION_COORDS['4-3-3'];return `<div class="pitch formation-${p.formation.replaceAll('-','')}">${FORMATIONS[p.formation].map((pos,i)=>{const x=p.team[i],r=x?rarityOf(x.overall):'',shortName=x?.name.split(/\s+/).slice(0,2).join(' ');return `<div class="slot ${x?'filled '+r:'empty'} ${preview?'preview-slot':''} ${x?.id===p.captainId?'captain-slot':''}" data-slot="${i}" style="left:${coords[i][0]}%;top:${coords[i][1]}%" ${x?`data-player-tooltip="${x.name} • OVR ${x.overall}" title="${x.name} • ${x.country} ${x.year} • OVR ${x.overall}"`:''}>${x?preview?`<span class="slot-overall">${x.overall}</span>${avatar()}<b>${shortName}</b>`:`${avatar()}<b>${x.name}</b><small>${positionLabel(pos)} • ${x.overall}</small>`:`<b>${positionLabel(pos)}</b>`}</div>`}).join('')}</div>`}
async function loadRound(useReroll=false){const p=activePlayer();if(game.locked)return;if(useReroll&&!p.rerolls)return;game.locked=true;renderLoading();const countries=['Brasil','Argentina','Alemanha','Itália','França','Espanha','Uruguai','Holanda','Inglaterra','Portugal','Croácia','Bélgica','Japão'],years=[1950,1966,1970,1974,1982,1986,1990,1994,1998,2002,2006,2010,2014,2018,2022];try{p.current=drawRound(p);if(useReroll)p.rerolls--;for(let i=0;i<DRAW_COUNTRY_TICKS;i++){document.querySelector('#searchCountry').textContent=countries[i%countries.length];await sleep(DRAW_TICK_MS)}document.querySelector('#searchCountry').textContent=p.current.country;await sleep(DRAW_SETTLE_MS);for(let i=0;i<DRAW_YEAR_TICKS;i++){document.querySelector('#searchYear').textContent=years[i%years.length];await sleep(DRAW_TICK_MS)}document.querySelector('#searchYear').textContent=p.current.year;document.querySelector('.search-state small').textContent='Preparando jogadores...';await sleep(DRAW_SETTLE_MS);await draft()}catch(error){game.locked=false;shell(`<section class="screen"><div class="panel error"><h2>Não foi possível montar esta rodada</h2><p>${error.message}</p><button class="btn primary" data-retry>Tentar novamente</button></div></section>`);document.querySelector('[data-retry]').onclick=()=>loadRound(false)}}
function renderLoading(){const p=activePlayer();shell(`<section class="screen"><div class="section-head"><div><div class="step">RODADA ${p.round+1} / 11</div><h2>Procurando seleção histórica...</h2></div><span class="pill">Rerolls restantes: ${p.rerolls}</span></div><div class="search-state"><span class="search-ball">◆</span><div class="search-result"><b id="searchCountry">Buscando...</b><strong id="searchYear">—</strong></div><small>Sorteando seleção e edição da Copa</small></div></section>`,'is-loading')}
async function legendaryPackReveal(card){shell(`<section class="screen legendary-pack-screen"><div class="legendary-pack"><div class="legendary-rays"></div><div class="legendary-pack-card"><span>LENDÁRIO</span><strong>${card.overall}</strong><i>${avatar()}</i><h2>${card.name}</h2><small>${card.country} • ${card.year}</small></div><p>UMA LENDA FOI ENCONTRADA</p></div></section>`,'legendary-opening');playTone(520,.18);await sleep(900);playTone(680,.2);await sleep(900);playTone(880,.32);await sleep(1050)}
