function askPenaltyAccuracy(event){return new Promise(resolve=>{const box=document.querySelector('#matchDecision');if(!box){resolve({accuracy:.65});return}box.hidden=false;const width=Math.max(20,Math.min(52,Number(event.greenWidth)||32));box.innerHTML=`<div class="accuracy-game"><span class="eyebrow">PRECISÃO DA COBRANÇA</span><h2>Pare o marcador na área verde</h2><div class="accuracy-track" style="--green:${width}%"><i></i><b></b></div><button class="btn primary" data-stop-accuracy>CHUTAR</button><small>Toque ou clique. Quanto mais perto do centro, melhor.</small></div>`;const marker=box.querySelector('.accuracy-track b'),started=performance.now();let frame,done=false;const animate=now=>{const progress=((now-started)%1800)/1800,position=progress<.5?progress*200:(1-progress)*200;marker.style.left=`${position}%`;frame=requestAnimationFrame(animate)};const finish=()=>{if(done)return;done=true;cancelAnimationFrame(frame);const position=parseFloat(marker.style.left)||0,accuracy=Math.max(0,1-Math.abs(position-50)/50);box.hidden=true;resolve({accuracy})};box.querySelector('[data-stop-accuracy]').onclick=finish;frame=requestAnimationFrame(animate);setTimeout(finish,event.timeout||9000)})}
function askShootoutOrder(event){return new Promise(resolve=>{const box=document.querySelector('#matchDecision');if(!box){resolve({orderedIds:[]});return}box.hidden=false;const order=[];box.innerHTML=`<div><span class="eyebrow">ORDEM DOS PÊNALTIS</span><h2>Escolha os cinco cobradores</h2><div class="penalty-order">${event.candidates.map(card=>`<button data-order="${card.id}"><i></i><b>${card.name}</b><small>OVR ${card.overall}</small></button>`).join('')}</div><button class="btn primary" data-confirm-order disabled>Confirmar ordem</button><small>1º ao 5º • o overall do cobrador e do goleiro influenciam.</small></div>`;let done=false;const finish=()=>{if(done)return;done=true;clearTimeout(timeout);box.hidden=true;resolve({orderedIds:order})},confirm=box.querySelector('[data-confirm-order]');box.querySelectorAll('[data-order]').forEach(button=>button.onclick=()=>{const id=button.dataset.order,index=order.indexOf(id);if(index>=0)order.splice(index,1);else if(order.length<5)order.push(id);box.querySelectorAll('[data-order]').forEach(item=>{const position=order.indexOf(item.dataset.order);item.classList.toggle('active',position>=0);item.querySelector('i').textContent=position>=0?position+1:''});confirm.disabled=order.length!==5});confirm.onclick=finish;const timeout=setTimeout(()=>{if(order.length<5)event.candidates.forEach(card=>{if(order.length<5&&!order.includes(card.id))order.push(card.id)});finish()},event.timeout||15000)})}
