async function simulate(){const local=game.players.player1,rival=game.mode==='local'?game.players.player2:game.opponent,homeEntry=local.side==='home'?local:rival,awayEntry=local.side==='away'?local:rival,userSide=local.side,label=entry=>entry===local?(game.mode==='local'?'JOGADOR 1':'VOCÊ'):(game.mode==='local'?'JOGADOR 2':game.mode==='online'?'RIVAL ONLINE':'WORLD XI');if(game.mode==='online'&&online.role==='guest'){online.watching=true;pollOnlineRoom();return}currentMatchLabels={home:label(homeEntry),away:label(awayEntry)};if(game.mode==='online')await updateOnlineMatch({phase:'kickoff',minute:0,score:{home:0,away:0},logs:['Aguardando o apito inicial...'],stats:{home:{},away:{}},momentum:{home:0,away:0},series:{...game.series,format:game.matchFormat}});shell(`<section class="screen kickoff"><div><span>JOGO ${game.series.game}</span><h2>${label(homeEntry)}</h2><b>VS</b><h2>${label(awayEntry)}</h2><p>Capitães em campo • ${game.matchFormat==='best3'?'MELHOR DE 3':'PARTIDA ÚNICA'}</p></div></section>`);await sleep(2200);const powered=entry=>{const details=teamPower(entry),boost=details.power-details.average;return entry.team.map(card=>({...card,overall:Math.round((card.overall+boost)*10)/10}))},home=powered(homeEntry),away=powered(awayEntry);renderMatchShell(label(homeEntry),label(awayEntry));const seed=`${game.mode==='online'?online.code:home.map(card=>card.id).join()}|${away.map(card=>card.id).join()}|${game.series.game}`;const result=await runMatch({home,away,seed,onUpdate:async state=>{state.series={...game.series,format:game.matchFormat};renderMatchState(state);await updateOnlineMatch(state)},onDecision:async event=>{if(game.mode==='online')return hostDecision(event);if(game.mode==='local')return passAndPlayDecision(event);if(event.side===userSide)return askLocalDecision(event);return automaticDecision(event)}});const homeWon=result.score.home>result.score.away||(result.score.home===result.score.away&&result.shootout?.home>result.shootout?.away);game.series[homeWon?'home':'away']++;const seriesOver=game.matchFormat==='single'||game.series.home===2||game.series.away===2,actions=document.querySelector('#matchFinalActions');if(!seriesOver){actions.innerHTML=`<span class="series-score">SÉRIE ${game.series.home}–${game.series.away}</span><button class="btn primary" data-next-match>Próximo jogo →</button>`;document.querySelector('[data-next-match]').onclick=()=>{game.series.game++;simulate()}}else{actions.innerHTML=`<span class="series-score">${game.matchFormat==='best3'?`SÉRIE FINAL ${game.series.home}–${game.series.away}`:'FIM DE JOGO'}</span><button class="btn primary" data-rematch>Revanche</button><button class="btn" data-home>Novo draft</button>`;document.querySelector('[data-rematch]').onclick=()=>{game.series={home:0,away:0,game:1};simulate()};bind()}}
function bind(){document.querySelectorAll('[data-home]').forEach(x=>x.onclick=()=>{clearOnline();resetGame();home()});document.querySelectorAll('[data-mode]').forEach(x=>x.onclick=()=>{clearOnline();resetGame(x.dataset.mode);x.dataset.mode==='solo'?chooseDifficulty():chooseSide()});document.querySelector('[data-online]')?.addEventListener('click',onlineMenu);document.querySelector('[data-players]')?.addEventListener('click',playerExplorer);document.querySelectorAll('[data-formation]').forEach(x=>x.onclick=()=>{const p=activePlayer();p.formation=x.dataset.formation;if(game.mode!=='online'){p.draftDeadline=Date.now()+DRAFT_TIMER_MS;startDraftTimer(p.draftDeadline,false)}syncOnline();loadRound()});document.querySelectorAll('[data-pick]').forEach(x=>x.onclick=()=>selectCard(+x.dataset.pick,x));document.querySelector('[data-reroll]')?.addEventListener('click',()=>loadRound(true));document.querySelectorAll('[data-coach]').forEach(x=>x.onclick=()=>finishCoach(x.dataset.coach));document.querySelector('[data-sim]')?.addEventListener('click',simulate);document.querySelector('[data-info]')?.addEventListener('click',()=>toast('Escolha 11 jogadores compatíveis, um treinador e dispute a partida final.'))}
